const today = new Date();
today.setHours(0, 0, 0, 0);

const warningDays = 30;

const expiryFields = [
  { field: 'Insurance Date',  label: '🛡️ Insurance' },
  { field: 'MOT Date',        label: '🔧 MOT / Inspection' },
  { field: 'Road Tax Date',   label: '💶 Road Tax' },
  { field: 'Service Date',    label: '🔩 Service' }
];

const alerts = [];

for (const row of $input.all()) {
  const vehicle  = row.json;
  const plate    = vehicle['Plate']    || 'N/A';
  const model    = vehicle['Model']    || '';
  const driver   = vehicle['Driver']   || '';

  for (const { field, label } of expiryFields) {
    const raw = vehicle[field];
    if (!raw) continue;

    const expiry = new Date(raw);
    if (isNaN(expiry)) continue;
    expiry.setHours(0, 0, 0, 0);

    const diffMs   = expiry - today;
    const diffDays = Math.round(diffMs / (24 * 60 * 60 * 1000));

    if (diffDays < 0) {
      alerts.push({
        json: {
          plate, model, driver,
          type: label,
          expiry: expiry.toLocaleDateString('en-GB'),
          days: diffDays,
          status: '🔴 EXPIRED'
        }
      });
    } else if (diffDays <= warningDays) {
      alerts.push({
        json: {
          plate, model, driver,
          type: label,
          expiry: expiry.toLocaleDateString('en-GB'),
          days: diffDays,
          status: diffDays <= 7 ? '🟠 URGENT' : '🟡 EXPIRING SOON'
        }
      });
    }
  }
}

if (alerts.length === 0) {
  return [{ json: { noAlerts: true } }];
}

return alerts;
